var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"일개 회사원에게, 아침 출근길은 괴롭다.","JPN":"一介の会社員に、朝の出勤は辛い。","ENG":"Morning commutes are torture for a normal officer worker like me.","TWN":"上班族早上通勤的時間真的有夠痛苦。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"자도 자도 풀리지 않는 피로감.\\n어쩔 수 없다는 말에 묶여 있는 수많은 일감들.\\n그리고 이 꽉 막힌 도로.","JPN":"いくら寝ても解消されない疲労。\\n仕方ないという言葉で括られた多くの仕事。\\nそしてこの混雑した道路。","ENG":"I'm exhausted no matter how much I sleep...\\nWork just keeps piling up...\\nAnd now this traffic jam...","TWN":"怎麼睡都無法消除的疲勞感，\\n做不完的工作，\\n再加上這條塞到爆的路。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"앞차 창문을 두드리면서 제발 좀 빠릿빠릿하게 가라고 한바탕 퍼부어 주고 싶다.","JPN":"前の車の窓をノックして、とっとと進めとひとこと言ってやりたい。","ENG":"I want to just go up to the car in front of me and yell at him to go faster.","TWN":"真想敲前面的車窗，對車上的人怒吼：給我開快一點！！"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 가슴 속에는 그럴 만한 담력 대신 부르르 우는 핸드폰만 남아 있다.","JPN":"だがそんな度胸はなく、あるものといえば胸ポケットでぶるぶる震えるケータイだけだった。","ENG":"But instead of having the courage to do so, the only thing I have is my phone which yells at me to pick it up.","TWN":"但在我身上有的不是膽量，而是響個不停的手機。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE_2"},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>급히 처리해야 할 일이 있습니다. 어서 출근하세요.</color>","JPN":"<color=#ffd34c>至急処理しなければならない仕事があります。早く出勤してください。</color>","ENG":"<color=#ffd34c>There's an urgent matter that needs to be dealt with. Please come in quick.</color>","TWN":"<color=#ffd34c>有急事找你，趕快進公司。</color>"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"울고 싶다.","JPN":"泣きたい。","ENG":"I wanna cry.","TWN":"真想哭。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"꿈과 희망과 환상과 모험과 신비와 쾌락의 <color=#ffd34c>헤이븐 랜드</color>!","JPN":"夢・希望・幻想・冒険・神秘・快楽の<color=#ffd34c>ヘイブンランド</color>！","ENG":"<color=#ffd34c>Havenland</color>! All of your hopes and dreams, fantasies and adventures, mysteries and pleasures await you here!","TWN":"充滿夢想、希望、奇幻、冒險、神秘和歡樂的<color=#ffd34c>天堂樂園</color>！"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"모든 감각을 만족시킬 만한 지상, 아니 상공 최대의 차원 함선!!","JPN":"すべての感覚を満足させてくれる地上、いや、上空最大の次元艦船！！","ENG":"The largest dimensional ship on the planet– No! Up in the air! Where you can satisfy all of your senses!","TWN":"滿足你所有感官的地上…，不，是空中最大次元艦船！！"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"헤이븐 랜드에서 새로운 이벤트가 개최됩니다.","JPN":"ヘイブンランドで新しいイベントが開催されます。","ENG":"A new event is being held in Havenland!","TWN":"天堂樂園全新活動開跑。"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"남녀노소 누구나 참여 가능! 참여만 해도 경품이 이렇게나!","JPN":"老若男女、誰でも参加できる！　参加するだけでも豪華景品が！","ENG":"Anyone can participate! All you need to do is join to get marvelous prizes!","TWN":"無論男女老少皆可參加！凡是參加就可以獲得這麼多贈品！"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"특별한 도전, 특별한 만남, 그리고 특별한 순간을 헤이븐 랜드에서!","JPN":"特別な挑戦、特別な出会い、そして特別な瞬間を、ヘイブンランドで！","ENG":"Come to Havenland for a special challenge, a special encounter, and a special time!","TWN":"特別的挑戰，特別的相遇，特別的瞬間，都在天堂樂園！"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>다음 헤이븐은 바로 당신입니다.</color>","JPN":"<color=#ffd34c>次のヘイブンはあなたです。</color>","ENG":"<color=#ffd34c>The next Haven is you.</color>","TWN":"<color=#ffd34c>下一個天堂就是你！</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>라스트 헤이븐</color>","JPN":"<color=#ffd34c>ラストヘイブン</color>","ENG":"<color=#ffd34c>Last Haven</color>","TWN":"<color=#ffd34c>最後的天堂</color>"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"웨이터?","JPN":"ウェイター？","ENG":"Waiter?","TWN":"服務生？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BAR_NPC_HAVEN_NULL","text":{"KOREA":"정확히는 바텐더, 입니다. 손님.","JPN":"正確にはバーテンダーです、お客様。","ENG":"Miss, it's \\"bartender\\", if you will.","TWN":"這位客人，正確來說我是酒保，不是服務生。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BAR_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"크흠. 바텐더, 깊이 있는 위스키로 한 잔 부탁해.","JPN":"こほん。バーテンダー、深みのあるウイスキーを一杯。","ENG":"Ahem...! Bartender? Give me a glass of one of your finest whiskies.","TWN":"咳咳，酒保，給我來杯沉釀威士忌。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그럼 난 화끈한 보드카 한 병.","JPN":"じゃあ、私はキリっとしたウォッカを一瓶ね。","ENG":"I'll take a bottle of vodka.","TWN":"那給我來一瓶嗆烈的伏特加。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"나, 나는 토토랑 마실 와인으로!","JPN":"わ、私はトトと一緒に飲むワインで！","ENG":"A-and some wine for Toto and me!","TWN":"那…那我跟托托要紅酒！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"쬐끄만 것들이 술은 무슨 술이야.","JPN":"未成年なんだからお酒はダメでしょ。","ENG":"You guys can't be serious, right?","TWN":"你們幾個小鬼給我喝什麼酒！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"취하기라도 하면 어쩌게? 친구끼리 어깨동무하고 다니다 난간 밖으로 떨어질래?","JPN":"酔ったらどうするんだよ？　友達同士で肩組んで手すりの向こう側に落ちたい？","ENG":"What'll you do if you get drunk, huh? You want to put your arms around each other's shoulders and fall off the railing?","TWN":"萬一喝醉的話怎麼辦？你們是想一起手牽手跌到欄杆外嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"구체적인 지적 고마워.","JPN":"具体的な指摘をありがとう。","ENG":"Thanks for pointing that out.","TWN":"謝謝你如此明確的教訓。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그래도 글린다. 여긴 술집이잖아.","JPN":"でもグリンダ。ここ酒場でしょ？","ENG":"But Glinda, we're at a pub...","TWN":"可是格琳達，這裡不是喝酒的地方嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"리온 말이 맞아. 술집에서 술도 안 시키면 다들 이상하게 볼 거라고.","JPN":"リオンの言うとおりだ。酒場で酒を頼まない客なんて、みんな怪しく思うよ。","ENG":"Liona's right. Won't it be weird to not order booze at a pub?","TWN":"萊恩說的沒錯，來喝酒的地方不點酒，大家會覺得我們很可疑的。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이런 고급 바를 술집이라고 부르는 것부터가 너희들이 아직 애라는 증거야.","JPN":"こんな高級バーを酒場って呼んでる時点でアンタたちはまだ子どもだって言ってるの。","ENG":"Calling this fine establishment a pub, and not a bar, tells me everything about your age.","TWN":"竟然把這麼高級的酒吧稱為喝酒的地方，光憑這一點就可以知道，你們根本是沒見過世面的小鬼吧！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"비싼 술 말고 다른 거 시켜. 남은 헤이븐 코인도 얼마 없어.","JPN":"高いお酒じゃなくて、別のもの頼みな。残ったヘイブンコインも少ないから。","ENG":"Order something other than expensive booze. We don't have that many Haven Coins left.","TWN":"不准點貴的酒，喝別的！我身上沒剩多少天堂幣。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그럼…… 톡 쏘는 제로 콜라로.","JPN":"じゃあ……シュワシュワのゼロコーラで。","ENG":"Then... I'll have a sparkling diet coke.","TWN":"那就來杯刺激的……零卡可樂吧。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"얄팍한 핫초코.","JPN":"薄めのホットチョコレート。","ENG":"I'll get the flimsy hot chocolate.","TWN":"我要清淡的熱巧克力。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그럼 난 나 혼자 마실 바닐라 쉐이크…….","JPN":"じゃあ私は一人で飲むバニラシェイク……","ENG":"Then I want a whole vanilla milkshake to myself...","TWN":"那我自己要喝香草奶昔……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"난 냉수 한 잔 마실게.","JPN":"私は水で。","ENG":"I'll have a cup of water.","TWN":"給我來杯冰水。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"BAR_NPC_HAVEN_NULL","text":{"KOREA":"잠시만 기다리세요. 금방 내오겠습니다.","JPN":"少々お待ちください。すぐお出します。","ENG":"Of course. I'll be back with your drinks shortly.","TWN":"好的，飲料等下就送過來。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BAR_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"잘 들어, 너희들. 분위기에 취한 건 알겠는데 우리가 왜 여기 왔는지 잊지 마.","JPN":"アンタたち、よく聞いて。ムードに酔うのはわかるけど、なんでここに来たのかを忘れないでよ。","ENG":"Listen up. I know you guys are excited about being here, but don't forget what our objective is, okay?","TWN":"你們給我聽好，我知道這裡的氣氛很醉人，但不要忘記我們來的目的是什麼。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"당연하지. 그걸 어떻게 잊어.","JPN":"当たり前だろ。忘れるはずないよ。","ENG":"Don't worry. How could we forget.","TWN":"那當然，我們怎麼可能會忘。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"응. 이용당하는 위저드 아이들을 구하려고 온 거지.","JPN":"うん。利用されてるウィザードの子たちを助けに来たんだよね。","ENG":"OK. We're here to save the Wizard children that are being exploited here.","TWN":"嗯，我們是來救那些被巫師利用的小孩的。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……알면서 술이나 시키고 있냐?","JPN":"……わかってるくせにお酒なんか頼んでたの？","ENG":"...Then why did you try to order alcohol?!","TWN":"……那你們明知道還點酒？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"하아. 안 가겠다는 사람 붙잡더니 결국 보모 노릇이나 하라는 거잖아.","JPN":"はあ。行かないって言ったのに連れてこられて、結局子守りをしているなんて。","ENG":"*Sigh* You dragged me here just so I could be your babysitter?","TWN":"哀，硬逼人家來，結果根本是叫我來當保母的嘛！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"내 꿈이었던 바니걸 언니들이 눈앞에 있는데…….","JPN":"私の夢だったバニーガールさんたちが目の前にいるってのに……","ENG":"But my dream of befriending bunny girls is right in front of me...","TWN":"人家夢寐以求的兔女郎就近在眼前……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"지금 헤이븐 랜드에선 이벤트가 한창이야.","JPN":"今ヘイブンランドはイベントの真っ最中よ。","ENG":"Havenland is holding an event right now.","TWN":"現在是天堂樂園的活動旺季。"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"알아. 블랙 네트워크 전체에 광고를 쫙 뿌렸거든.","JPN":"知ってる。ブラックネットワーク全体に宣伝がばらまかれてたから。","ENG":"I know. There are ads all over the Dark Network.","TWN":"我知道，他們的廣告充斥在整個黑色網路上。"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"게시글 확인하다가 그 광고만 정확히 1127번째 확인했어.","JPN":"書き込みを確認するときに、その宣伝だけでも1127回は見た。","ENG":"I was looking at the posts and saw the ad exactly 1127 times.","TWN":"光是看個貼文，就已經看到1127次他們的廣告。"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"그래. 혼란한 틈을 타서 침입하기에 안성맞춤이란 뜻이지.","JPN":"そう。混乱に乗じて進入するには打ってつけってことよ。","ENG":"Yeah. It's the perfect time to sneak into that place, don't you think?","TWN":"沒錯，意思就是，現在是趁亂潛入的好時機！"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"다들 이벤트에 정신 팔려 있는 동안 엔진실에 잠입해야 돼.","JPN":"みんながイベントに夢中になってる間にエンジンルームに潜入するの。","ENG":"While everyone is preoccupied with the event, we will enter the engine room.","TWN":"趁他們忙著辦活動時，潛入引擎室。"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"잠입하고 나선?","JPN":"潜入した後は？","ENG":"And after that?","TWN":"潛入後呢？"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"엔진을 정지시키면 함선도 불시착하려 할 거야. 예상 도착 좌표를 나에게 보내 주면 돼.","JPN":"エンジンを停止させれば艦船も不時着しょうとするはずよ。予想到着座標を私に送ってくれればいい。","ENG":"We'll stop the engine and crash-land the ship. All you need to do is send me the expected coordinates.","TWN":"只要讓引擎停止運作，艦船就必須緊急迫降，到時你們再把預計降落的座標傳給我就好。"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"아…… 역시 지금이라도 그만 둘까. 애들 떼쓴다고 휘둘리는 기분인데.","JPN":"あ……やっぱり今からでもやめようかな。この子たちのわがままにどうも振り回されてる気がするのよね。","ENG":"Should I just abort it now...? I feel like I'm being swayed by these kids...","TWN":"呃……還是乾脆算啦？有點把事情推給她們的感覺。"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그럼 관리국 정보부가 나서는 거야? 전엔 어렵다고 했잖아.","JPN":"じゃあ、管理局の情報部が出てくるの？　この前は難しいって言ってたけど。","ENG":"Then, will the Administration Intelligence Agency step in? Didn't you say that would be difficult?","TWN":"那是管理局情報部會出手的意思嗎？之前不是說沒辦法嗎？"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"그게…….","JPN":"それが……","ENG":"Well...","TWN":"這個……"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"솔직히 말할게. 아직 확답은 못 들었어.","JPN":"正直に話すね。まだはっきりとした答えは聞けてないの。","ENG":"I'll be honest with you. They didn't answer back yet.","TWN":"坦白說，我也無法保證。"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"헤이븐은 급부상한 녀석이라 정보가 적어.","JPN":"ヘイブンは急浮上してきたやつだから、情報が少ないのよ。","ENG":"Haven just sort of appeared out of nowhere, so we don't have much intel on him.","TWN":"天堂是在短時間內竄起來的人物，有關他的情報不多。"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"본거지인 헤이븐 랜드는 오비탈 베이스용으로 생산되던 프레임을 훔쳐다 만든 거라, 요격도 힘들고.","JPN":"本拠地のヘイブンランドはオービタルベース用に生産されたフレームを盗んで作ったものだから、迎撃も難しいし。","ENG":"And his ship, Havenland, is made by stealing the frame of an Orbital Base, so it'll be difficult to shoot down, as well...","TWN":"而他的據點天堂樂園，是竊取生產給軌道基地使用的機體後改造而成的，本身就很難攻破。"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"게다가 제일 큰 문제는 녀석이 검은 평의회 소속이 됐다는 거야.","JPN":"それに一番の問題は、やつが黒の評議会所属になったってことよ。","ENG":"Yet the biggest problem is that he became a member of the Dark Council.","TWN":"但最大的問題是，那傢伙是黑暗評議會的人。"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"상부에는 괜히 건드렸다가 평의회와의 전면전으로 비화될까 봐 걱정하는 사람도 많아.","JPN":"上層部ではうかつに刺激して、評議会との全面戦争になるのではと心配してる人も多いの。","ENG":"The higher-ups are concerned that it'll spark an all-out war with the Dark Council if we start going after him.","TWN":"上頭有許多人都擔心，沒事去招惹他，會演變成和評議會之間的正面衝突。"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"검은 평의회……? 뭐 마피아 같은 조직이야?","JPN":"黒の評議会……？　何それ、マフィアみたいな組織？","ENG":"The Dark Council...? What is that? Some kind of mafia?","TWN":"黑暗評議會……？是像黑手黨那樣的組織嗎？"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"옛날부터 존재해 온 국제 범죄 카르텔이야. 범죄자들의 우상이랄까.","JPN":"昔からあった国際犯罪カルテルよ。犯罪者のアイドル的存在ってとこ。","ENG":"They are an international criminal cartel that's been around for ages. Criminals look up to them like idols.","TWN":"他們是從很久以前就存在的國際犯罪集團，可以說是犯罪者的最高殿堂吧？"},"stage":{"bg":"ALPHA_07","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"현재로서는 규모도, 전력도 미지수. 당장 스캐빈저도 그쪽 소속이야.","JPN":"現時点では規模も戦力も未知数。スカベンジャーもそっちに所属してるわ。","ENG":"Currently, we don't know how big or powerful they are. One thing we do know is that Scavengers are also a part of them.","TWN":"沒人清楚他們現在的規模和戰力，就連清道夫也隸屬於他們。"},"stage":{"bg":"ALPHA_07","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그럼… 우리가 애들을 구해도 어른들은 못 도와준다는 거야?","JPN":"じゃあ……救出しても大人たちは助けてくれないってこと？","ENG":"Then... Even if we save the children, adults aren't going to help?","TWN":"那…就算我們把那些孩子救出來，大人們也無法幫忙嗎？"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"……뭐래, 얘는. 그래서 내가 안 따라가고 남는 거잖아.","JPN":"……何言ってるのかしら、この子は。だから私が一緒に行かずにここに残るんでしょ。","ENG":"…What are you talking about? That's why I'm staying here and not going with you guys.","TWN":"……你在說什麼，所以我不是沒跟去，而是留在這裡嗎？"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"마크 아저씨는 내 편이야. 어떻게든 상부를 설득할 테니까 너희 할일이나 잘하라구.","JPN":"マークおじさんは味方よ。何としてでも上層部を説得するから、あんたたちはあんたたちのやることをしっかりやって。","ENG":"Mark's on my side. He and I'll try to persuade the higher-ups, so you should do what you can over there.","TWN":"馬克大叔是站在我這邊的，我一定會想辦法說服上面的人，你們只要做好自己的事就好！"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"알겠어. 그럼 부탁할게.","JPN":"わかった。じゃあ、よろしく。","ENG":"All right. We're counting on you.","TWN":"好吧，那就麻煩囉。"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"격납고를 경유해서 엔진실로 가야 해. 우리 쪽 협력자가 거기서 합류하기로 했어.","JPN":"格納庫を経由してエンジンルームまで行く。協力者がそこで合流する予定だよ。","ENG":"We need to head to the hangar then the engine room. That's where we agreed to meet our cooperator.","TWN":"必須經過機庫再潛入引擎室，已經和幫手約好在那裡會合。"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"믿을 만한 상대인 거 정말 확실하지?","JPN":"本当に信頼できる相手なのね？","ENG":"You're sure we can trust this person, right?","TWN":"確定對方是信得過的吧？"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"다시 말하는데 진짜 위험한 짓이야. 마음 같아선 때려 눕혀서라도 말리고 싶을 정도라구.","JPN":"もう一度言うけど本当に危ないのよ。できれば殴り倒してでもやめさせたいくらい。","ENG":"What you're doing is very dangerous. Honestly, I don't want to let you do that.","TWN":"我再重申一次，這次的行動真的很危險，要是可以的話，我寧願打暈你們也不想你們去。"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"헤이븐 랜드에서는 아무도 너희들 안전을 보장해 줄 수가 없어.","JPN":"ヘイブンランドでは、誰もあんたたちの安全を保障できないわ。","ENG":"No one can vouch for your safety in Havenland.","TWN":"沒有人能夠保證你們在天堂樂園裡的安全。"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"저기. 다 좋은데.","JPN":"あのさ。ちょっといいかな。","ENG":"Yeah. That's good and all, but...","TWN":"那個，你們想怎麼樣都好，"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"내가 왜 여기 있는 건지 말해 줄 사람?","JPN":"誰か、なんで私がここにいるのかを説明してくれない？","ENG":"Can anyone tell me why I'm here?","TWN":"不過有人可以告訴我，我為什麼會在這裡嗎？"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"왜긴 왜야. 너도 얘들이랑 같이 가야 하니까 불렀지.","JPN":"なんでって、あんたもこの子たちと一緒に行かないとダメだから呼んだのよ。","ENG":"What do you mean? You're here because you're gonna go with them.","TWN":"什麼為什麼？當然是因為你要和她們一起去才找你來的！"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아니, 그게 무슨 말도 안 되는 억지야?! 내가 가서 뭘 할 수 있는데?","JPN":"いや、私の意見は！？　それに私に何ができるってのよ？","ENG":"Wait... What's that supposed to mean?! What good could I do over there?","TWN":"什麼？哪有人這樣強迫中獎的？！我去是能做什麼？"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"글린다는 우리 중에 제일 나이가 많잖아. 헤이븐 랜드 워너비였고.","JPN":"グリンダは私たちの中で一番年上だろ。それにヘイブンランドのファンだったし。","ENG":"Glinda, you're the oldest out of all of us. Plus, you always wanted to go to Havenland, right?","TWN":"格琳達是我們當中年紀最大的，而且又曾經那麼熱愛天堂樂園。"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"맞아. 밤마다 잠꼬대로 헤이븐 노래를 부를 정도였어.","JPN":"うん。毎晩寝言でヘイブンの歌を歌ってるほどだ。","ENG":"Yeah. You even sleep talk about it every night.","TWN":"對，愛到每天晚上做夢都在哼天堂的歌。"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"애들은 좀 빠져 있으셔.","JPN":"子どもは黙ってなさいよ。","ENG":"Kids, can't you see the adults are talking?","TWN":"你們可以迴避一下嗎？"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"어…… 내가 별난 곳에 잠입했던 경험을 토대로 하는 말인데.","JPN":"えっと……私がちょっと変わったところに潜入した経験から話すことなんだけど。","ENG":"Uh... From my experience with going into places where I'm not supposed to...","TWN":"呃……根據我潛入過其他地方的經驗，"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"얘네들끼리만 들여보내면 입구에서부터 들통날 걸?","JPN":"この子たちだけで行かせるとたぶん入り口でバレる。","ENG":"If we send just the kids, they'll be detected as soon as they set foot in there.","TWN":"只派她們去的話，應該在大門口就會被逮到吧？"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"누군가는 길잡이 역할을 해 줄 사람이 필요해.","JPN":"誰か道しるべになってくれる人が必要なの。","ENG":"Besides, we also need someone to act as the guide around there.","TWN":"需要有人替她們帶路。"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……. 아, 진짜. 미운 오리새끼만 세트로 셋이야.","JPN":"……ああ、もう。ヤンチャ三人組のセットだなんて。","ENG":"Ah, geez... I have to watch over Huey, Dewey, and Louie?","TWN":"……真是的，三個拖油瓶。"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"알았으니까 루루나 잘 챙겨 줘. 기운을 차리려면 오래 걸릴 테니까.","JPN":"わかったから、ルルのこと頼むよ。元気になるまで時間かかるだろから。","ENG":"Fine. Then look after Lulu for me, okay? It might take a while for her to get better.","TWN":"知道啦，那你幫我照顧好露露，她要很長一段時間才能恢復體力。"},"stage":{"bg":"DATABASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"일어나자. 곧 합류하기로 한 시간이야.","JPN":"行こう。もう合流する時間でしょ。","ENG":"C'mon. It's almost time.","TWN":"走吧，快到約定會合的時間了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"눈에 띄는 짓 하지 말고 얌전히 따라와.","JPN":"目立つことしないで、大人しくついてきて。","ENG":"Don't do anything stupid, and just follow me.","TWN":"安靜跟我來，別被人發現。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"졸린가 보군. 피곤한가?","JPN":"眠そうだな。疲れているのか？","ENG":"You seem tired. Too much work?","TWN":"你好像有點睏，很累嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BAR_NPC_HAVEN_NULL","text":{"KOREA":"죄, 죄송합니다. 휴스턴님. 어제도 철야를 해서 그만……","JPN":"も、申し訳ありません。ヒューストン様。昨日も徹夜でしたので、つい……","ENG":"O-oh, Mr. Huston... I'm sorry. I just had to work all night yesterday as well, and…","TWN":"抱…抱歉，休士頓先生，昨天也是熬夜……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BAR_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"다들 그렇지. 조금만 참아.","JPN":"みんなそうだろう。もう少しの我慢だ。","ENG":"Aren't we all? Hang in there.","TWN":"大家都一樣，再忍耐一下。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"여기 앉아 있던 손님들이 뭘 주문했지?","JPN":"ここに座っていたお客様は何を頼んだんだ？","ENG":"By the way, what did the customers who sat here order?","TWN":"剛才坐在這裡的客人點了什麼？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BAR_NPC_HAVEN_NULL","text":{"KOREA":"제로 콜라, 핫초코, 바닐라 쉐이크, 그리고 냉수 한 잔이었습니다.","JPN":"ゼロコーラ、ホットチョコレート、バニラシェイク、そして水を一杯注文しました。","ENG":"A diet coke, hot chocolate, vanilla shake, and a glass of water, sir.","TWN":"零卡可樂，熱巧克力，香草奶昔，和一杯冰水。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BAR_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"상당히 소박한 메뉴뿐이군.","JPN":"素朴なメニューばかりだな。","ENG":"That's a rather humble order.","TWN":"這麼樸素。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BAR_NPC_HAVEN_NULL","text":{"KOREA":"술 약한 손님들도 있으니까요. 일행 전부가 그런 경우는 드물지만요.","JPN":"お酒が弱いお客様もいますので。全員がそういう場合は珍しいですが。","ENG":"Well, there are customers who can't drink alcohol. Although, it is rare to see a whole group like that.","TWN":"有些客人是不喝酒的，但一群人都不喝酒是有點罕見。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BAR_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"흠…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"헤론이 알면 좋아하겠군. 좋은 기회야.","JPN":"ヘロンが聞けば喜ぶだろうな。いい機会だ。","ENG":"Heron would love to know about this. It's a good opportunity.","TWN":"海倫知道的話一定會很開心，這是個好機會。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};